from flask import Flask, redirect, url_for, session, request
import requests
import json
from authlib.integrations.flask_client import OAuth

app = Flask(__name__)
app.secret_key = 'your_secret_key'

oauth = OAuth(app)
auth0 = oauth.register(
    'auth0',
    client_id='YOUR_CLIENT_ID',
    client_secret='YOUR_CLIENT_SECRET',
    api_base_url='https://YOUR_DOMAIN',
    access_token_url='https://YOUR_DOMAIN/oauth/token',
    authorize_url='https://YOUR_DOMAIN/authorize',
    client_kwargs={
        'scope': 'openid profile email',
    },
)

@app.route('/')
def home():
    return 'Welcome to the Flask OpenID Connect Example'

@app.route('/login')
def login():
    return auth0.authorize_redirect(redirect_uri=url_for('callback', _external=True))

@app.route('/callback')
def callback():
    token = auth0.authorize_access_token()
    id_token = token.get('id_token')
    user_info = auth0.parse_id_token(token)
    session['user'] = {
        'name': user_info['name'],
        'email': user_info['email']
    }
    return redirect('/dashboard')

@app.route('/dashboard')
def dashboard():
    user = session.get('user')
    if user:
        return f"Hello, {user['name']}! You are logged in as {user['email']}."
    return redirect(url_for('login'))

@app.route('/logout')
def logout():
    session.clear()
    return redirect('https://YOUR_DOMAIN/v2/logout?returnTo=' + url_for('home', _external=True))

if __name__ == '__main__':
    app.run(debug=True)